const DialogPlaygroundExample = () => {
  const [dialogOpen, setDialogOpen] = useState(false)
  const openDialog = () => setDialogOpen(true)
  const closeDialog = () => setDialogOpen(false)

  return (
    <>
      <Button marginBottom="sm" onClick={openDialog}>
        Open Dialog
      </Button>
      {{component}}
    </>
  )
}

<DialogPlaygroundExample />

